SELECT DISTINCT ?country ?countryLabel ?winner ?winnerLabel
WHERE {
  ?edition wdt:P31 wd:Q864915;
           wdt:P134 wd:Q15147;
           wdt:P131 ?city;
           wdt:P128 ?winner;
           wdt:P585 ?year.
  ?city wdt:P131 ?country.
  ?country rdfs:label ?countryLabel.
  FILTER (lang(?countryLabel) = "en").
  ?winner rdfs:label ?winnerLabel.
  FILTER (lang(?winnerLabel) = "en").
}
ORDER BY DESC(?year)
LIMIT 1

